{
  "mode": "io",
  "tests": [
    {
      "name": "remove_mock_data",
      "input": {},
      "output": "No mock data present in the response.",
      "notes": "Validates that the application does not return any hardcoded/mock responses."
    },
    {
      "name": "api_failure_handling",
      "input": {},
      "output": "Error: Unable to fetch data from MCP.",
      "notes": "Confirms that a clear UI error message is displayed when the MCP API call fails."
    },
    {
      "name": "query_with_technology_keyword",
      "input": {"keyword": "JavaScript"},
      "output": [{"challenge_id": 1, "title": "JavaScript Challenge 1"}, {"challenge_id": 2, "title": "JavaScript Challenge 2"}],
      "notes": "Ensures that querying with a tech keyword returns expected challenge results."
    },
    {
      "name": "remove_skills_section",
      "input": {},
      "output": "Your Skills & Technologies section not found.",
      "notes": "Validates that the 'Your Skills & Technologies' section has been removed from the UI and backend."
    },
    {
      "name": "error_message_format",
      "input": {},
      "output": "Error: API call failed. Please try again later.",
      "notes": "Checks that the error message is user-friendly and minimal when an API call fails."
    },
    {
      "name": "empty_query_response",
      "input": {"keyword": ""},
      "output": "No challenges found for the given query.",
      "notes": "Tests the response when an empty query is submitted, ensuring proper handling."
    },
    {
      "name": "invalid_keyword_query",
      "input": {"keyword": "nonexistenttech"},
      "output": "No challenges found for the given query.",
      "notes": "Validates the response when an invalid technology keyword is queried."
    },
    {
      "name": "api_timeout_handling",
      "input": {},
      "output": "Error: Unable to fetch data from MCP due to timeout.",
      "notes": "Tests the application's behavior when the MCP API call times out."
    }
  ],
  "assumptions": "The MCP API is accessible and functional during testing.",
  "notes": "Ensure that the application is set up correctly with the necessary environment variables."
}
